using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationMetricsResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public class PerClassMetric
{
    public string Class { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext = new(seed: 42);
    private readonly string _modelPath;
    private readonly string _dataPath;
    private readonly ILogger<TicketClassifierService> _logger;
    private ITransformer? _model;
    private string[]? _classLabels;
    private EvaluationMetricsResponse? _evaluationMetrics;

    public TicketClassifierService(IWebHostEnvironment env, ILogger<TicketClassifierService> logger)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public EvaluationMetricsResponse? EvaluationMetrics => _evaluationMetrics;

    public void TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(split.TrainSet);

        // Extract class labels from the trained model's label column
        var schema = _model.GetOutputSchema(split.TrainSet.Schema);
        var labelColumn = schema["Label"];
        var labelType = labelColumn.Type as Microsoft.ML.Data.VectorDataViewType
            ?? labelColumn.Type as Microsoft.ML.Data.DataViewType;
        var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
        if (keyType is not null)
        {
            VBuffer<ReadOnlyMemory<char>> keyValues = default;
            labelColumn.GetKeyValues(ref keyValues);
            _classLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();
        }
        _classLabels ??= ["Billing", "General", "Technical"];

        // Evaluate on test set
        var predictions = _model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _evaluationMetrics = new EvaluationMetricsResponse
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerClassMetrics = metrics.PerClassLogLoss
                .Select((logLoss, i) => new PerClassMetric
                {
                    Class = i < _classLabels.Length ? _classLabels[i] : $"Class{i}",
                    Precision = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                    Recall = i < metrics.ConfusionMatrix.PerClassRecall.Count
                        ? metrics.ConfusionMatrix.PerClassRecall[i] : 0,
                    F1Score = ComputeF1(
                        i < metrics.ConfusionMatrix.PerClassPrecision.Count
                            ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                        i < metrics.ConfusionMatrix.PerClassRecall.Count
                            ? metrics.ConfusionMatrix.PerClassRecall[i] : 0)
                }).ToArray()
        };

        _logger.LogInformation(
            "Model trained — MacroAccuracy: {MacroAccuracy:F4}, MicroAccuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        _mlContext.Model.Save(_model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }

    public string[] GetClassLabels() => _classLabels ?? ["Billing", "General", "Technical"];

    public ITransformer GetModel() =>
        _model ?? throw new InvalidOperationException("Model has not been trained yet.");

    public DataViewSchema GetSchema()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
        return _model!.GetOutputSchema(data.Schema);
    }

    private static double ComputeF1(double precision, double recall) =>
        precision + recall > 0 ? 2 * precision * recall / (precision + recall) : 0;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly TicketClassifierService _classifierService;

    public TicketController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        TicketClassifierService classifierService)
    {
        _predictionPool = predictionPool;
        _classifierService = classifierService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);
        var labels = _classifierService.GetClassLabels();

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetricsResponse> GetMetrics()
    {
        var metrics = _classifierService.EvaluationMetrics;
        if (metrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(metrics);
    }
}

