21.         _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
22.     }
23. 
24.     public EvaluationMetricsResponse? EvaluationMetrics => _evaluationMetrics;
25. 
26.     public void TrainAndEvaluate()
27.     {
28.         var data = _mlContext.Data.LoadFromTextFile<TicketData>(
29.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
30. 
31.         var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
32. 
33.         var pipeline = _mlContext.Transforms.Text
34.                 .FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
35.             .Append(_mlContext.Transforms.Text
36.                 .FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
37.             .Append(_mlContext.Transforms.Concatenate("Features",
38.                 "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
39.             .Append(_mlContext.Transforms.Conversion
40.                 .MapValueToKey("Label", nameof(TicketData.Category)))
41.             .Append(_mlContext.MulticlassClassification.Trainers
42.                 .SdcaMaximumEntropy("Label", "Features"))
43.             .Append(_mlContext.Transforms.Conversion
44.                 .MapKeyToValue("PredictedLabel"));
45. 
46.         _model = pipeline.Fit(split.TrainSet);
47. 
48.         // Extract class labels from the trained model's label column
49.         var schema = _model.GetOutputSchema(split.TrainSet.Schema);
50.         var labelColumn = schema["Label"];
51.         if (labelColumn.Type is KeyDataViewType)
52.         {
53.             var keyValues = new VBuffer<ReadOnlyMemory<char>>();
54.             labelColumn.GetKeyValues(ref keyValues);
55.             _classLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();
56.         }
57.         _classLabels ??= ["Billing", "General", "Technical"];
58. 
59.         // Evaluate on test set
60.         var predictions = _model.Transform(split.TestSet);
61.         var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);
62. 
63.         _evaluationMetrics = new EvaluationMetricsResponse
64.         {
65.             MacroAccuracy = Sanitize(metrics.MacroAccuracy),
66.             MicroAccuracy = Sanitize(metrics.MicroAccuracy),
67.             LogLoss = Sanitize(metrics.LogLoss),
68.             LogLossReduction = Sanitize(metrics.LogLossReduction),
69.             PerClassMetrics = metrics.PerClassLogLoss
70.                 .Select((logLoss, i) => new PerClassMetric
71.                 {
72.                     Class = i < _classLabels.Length ? _classLabels[i] : $"Class{i}",
73.                     Precision = Sanitize(i < metrics.ConfusionMatrix.PerClassPrecision.Count
74.                         ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0),
