76.                         ? metrics.ConfusionMatrix.PerClassRecall[i] : 0),
77.                     F1Score = ComputeF1(
78.                         Sanitize(i < metrics.ConfusionMatrix.PerClassPrecision.Count
79.                             ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0),
80.                         Sanitize(i < metrics.ConfusionMatrix.PerClassRecall.Count
81.                             ? metrics.ConfusionMatrix.PerClassRecall[i] : 0))
82.                 }).ToArray()
83.         };
84. 
85.         _logger.LogInformation(
86.             "Model trained — MacroAccuracy: {MacroAccuracy:F4}, MicroAccuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
87.             metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);
88. 
89.         _mlContext.Model.Save(_model, split.TrainSet.Schema, _modelPath);
